// Summary of all checks
const items = $input.all();
const summary = {
  total: items.length,
  down: items.filter(i => i.json.isDown).length,
  slow: items.filter(i => !i.json.isDown && i.json.needsAlert).length,
  healthy: items.filter(i => !i.json.needsAlert).length
};

return [{ json: summary }];
